    export function slots_bet_list()
    {
        let tb = {
    	    bet_list : [],
    	    bet_line_list : [],
    	    multiple_list : [],
			getMsgID:function()
			{
   				return NetMsgType.msgType["msg_slots_bet_list"];
    		},
		    encode:function(buf)
		    {
       			EncodeUtils.uInt16ToByte(tb.bet_list.length, buf);
       			for (let i = 0; i < tb.bet_list.length; ++i)
				{
		    		EncodeUtils.int32ToByte(tb.bet_list[i], buf);
       			}
       			EncodeUtils.uInt16ToByte(tb.bet_line_list.length, buf);
       			for (let i = 0; i < tb.bet_line_list.length; ++i)
				{
		    		EncodeUtils.int32ToByte(tb.bet_line_list[i], buf);
       			}
       			EncodeUtils.uInt16ToByte(tb.multiple_list.length, buf);
       			for (let i = 0; i < tb.multiple_list.length; ++i)
				{
		    		EncodeUtils.int32ToByte(tb.multiple_list[i], buf);
       			}
    	    },
    		decode:function(buf, index)
			{
				let startIndex = index;
        		let bet_list_len = EncodeUtils.ByteToUint16(buf, startIndex);
        		startIndex += 2;
        		for(let i = 0; i < bet_list_len; ++i)
		 		{
             		tb.bet_list.push(EncodeUtils.ByteToint32(buf, startIndex));
					startIndex += 4;
        		}
        		let bet_line_list_len = EncodeUtils.ByteToUint16(buf, startIndex);
        		startIndex += 2;
        		for(let i = 0; i < bet_line_list_len; ++i)
		 		{
             		tb.bet_line_list.push(EncodeUtils.ByteToint32(buf, startIndex));
					startIndex += 4;
        		}
        		let multiple_list_len = EncodeUtils.ByteToUint16(buf, startIndex);
        		startIndex += 2;
        		for(let i = 0; i < multiple_list_len; ++i)
		 		{
             		tb.multiple_list.push(EncodeUtils.ByteToint32(buf, startIndex));
					startIndex += 4;
        		}
				return startIndex - index;
			},
    		build:function(buf)
			{
        		EncodeUtils.uInt32ToByte(NetMsgType.msgType["msg_slots_bet_list"], buf);
        		return tb.encode(buf);
    		}
		};
    	return tb;
	}
