    export function notify_register_moving_check()
    {
        let tb = {
    	    is_success : 0,
    	    message : '',
    	    url : '',
    	    y_pos : 0,
    	    promotion_url : [],
    	    seo_url : [],
			getMsgID:function()
			{
   				return NetMsgType.msgType["msg_notify_register_moving_check"];
    		},
		    encode:function(buf)
		    {
    		    EncodeUtils.int32ToByte(tb.is_success, buf);
    			EncodeUtils.utf8StrtoBytes(tb.message, buf);
    			EncodeUtils.utf8StrtoBytes(tb.url, buf);
    		    EncodeUtils.int32ToByte(tb.y_pos, buf);
       			EncodeUtils.uInt16ToByte(tb.promotion_url.length, buf);
       			for (let i = 0; i < tb.promotion_url.length; ++i)
				{
		    		EncodeUtils.utf8StrtoBytes(tb.promotion_url[i], buf);
       			}
       			EncodeUtils.uInt16ToByte(tb.seo_url.length, buf);
       			for (let i = 0; i < tb.seo_url.length; ++i)
				{
		    		EncodeUtils.utf8StrtoBytes(tb.seo_url[i], buf);
       			}
    	    },
    		decode:function(buf, index)
			{
				let startIndex = index;
        		tb.is_success = EncodeUtils.ByteToint32(buf, startIndex);
				startIndex += 4;
				let message_value = EncodeUtils.byteToString(buf, startIndex);
				tb.message = message_value[0];
 				startIndex += message_value[1];
				let url_value = EncodeUtils.byteToString(buf, startIndex);
				tb.url = url_value[0];
 				startIndex += url_value[1];
        		tb.y_pos = EncodeUtils.ByteToint32(buf, startIndex);
				startIndex += 4;
        		let promotion_url_len = EncodeUtils.ByteToUint16(buf, startIndex);
        		startIndex += 2;
        		for(let i = 0; i < promotion_url_len; ++i)
		 		{
					let promotion_url_value = EncodeUtils.byteToString(buf, startIndex);
					tb.promotion_url.push(promotion_url_value[0]);
					startIndex += promotion_url_value[1];
        		}
        		let seo_url_len = EncodeUtils.ByteToUint16(buf, startIndex);
        		startIndex += 2;
        		for(let i = 0; i < seo_url_len; ++i)
		 		{
					let seo_url_value = EncodeUtils.byteToString(buf, startIndex);
					tb.seo_url.push(seo_url_value[0]);
					startIndex += seo_url_value[1];
        		}
				return startIndex - index;
			},
    		build:function(buf)
			{
        		EncodeUtils.uInt32ToByte(NetMsgType.msgType["msg_notify_register_moving_check"], buf);
        		return tb.encode(buf);
    		}
		};
    	return tb;
	}
