        		startIndex += 2;
        		for(let i = 0; i < rank_prize_len; ++i)
				{
            		let tmp = prize_info();
            		startIndex += tmp.decode(buf, startIndex);
            		tb.rank_prize.push(tmp);
        		}
        		let marquee_len = EncodeUtils.ByteToUint16(buf, startIndex);
        		startIndex += 2;
