    export function notify_web_game_get_bet_record_list()
    {
        let tb = {
    	    total_pages : 0,
    	    bet_record_list : [],
    	    total_items : 0,
    	    total_bet : 0,
    	    total_stream : 0,
    	    total_net_value : 0,
    	    asyn_data : '',
			getMsgID:function()
			{
   				return NetMsgType.msgType["msg_notify_web_game_get_bet_record_list"];
    		},
		    encode:function(buf)
		    {
    		    EncodeUtils.int32ToByte(tb.total_pages, buf);
        		EncodeUtils.uInt16ToByte(tb.bet_record_list.length, buf);
        		for (let i = 0; i < tb.bet_record_list.length; ++i)
				{
            		tb.bet_record_list[i].encode(buf);
	     		}
    		    EncodeUtils.int32ToByte(tb.total_items, buf);
    			EncodeUtils.int64ToByte(tb.total_bet, buf);
    			EncodeUtils.int64ToByte(tb.total_stream, buf);
    			EncodeUtils.int64ToByte(tb.total_net_value, buf);
    			EncodeUtils.utf8StrtoBytes(tb.asyn_data, buf);
    	    },
    		decode:function(buf, index)
			{
				let startIndex = index;
        		tb.total_pages = EncodeUtils.ByteToint32(buf, startIndex);
				startIndex += 4;
        		let bet_record_list_len = EncodeUtils.ByteToUint16(buf, startIndex);
        		startIndex += 2;
        		for(let i = 0; i < bet_record_list_len; ++i)
				{
            		let tmp = web_game_bet_record();
            		startIndex += tmp.decode(buf, startIndex);
            		tb.bet_record_list.push(tmp);
        		}
        		tb.total_items = EncodeUtils.ByteToint32(buf, startIndex);
				startIndex += 4;
        		tb.total_bet = EncodeUtils.ByteToint64(buf, startIndex);
				startIndex += 8;
        		tb.total_stream = EncodeUtils.ByteToint64(buf, startIndex);
				startIndex += 8;
        		tb.total_net_value = EncodeUtils.ByteToint64(buf, startIndex);
				startIndex += 8;
				let asyn_data_value = EncodeUtils.byteToString(buf, startIndex);
				tb.asyn_data = asyn_data_value[0];
 				startIndex += asyn_data_value[1];
				return startIndex - index;
			},
    		build:function(buf)
			{
        		EncodeUtils.uInt32ToByte(NetMsgType.msgType["msg_notify_web_game_get_bet_record_list"], buf);
        		return tb.encode(buf);
    		}
		};
    	return tb;
	}
