				{
            		tb.userinfo[i].encode(buf);
	     		}
    		    EncodeUtils.int32ToByte(tb.bankchairid, buf);
    		    EncodeUtils.int32ToByte(tb.outcardchairid, buf);
    		    EncodeUtils.int32ToByte(tb.currentchairid, buf);
    		    EncodeUtils.int32ToByte(tb.bet_base, buf);
