    export function notify_baijiale_settlement()
    {
        let tb = {
    	    banker_cards : [],
    	    player_cards : [],
    	    banker_point : 0,
    	    player_point : 0,
    	    settlement_list : [],
    	    others_get_money : 0,
    	    record : 0,
    	    client_key : '',
    	    server_key : '',
    	    video : '',
			getMsgID:function()
			{
   				return NetMsgType.msgType["msg_notify_baijiale_settlement"];
    		},
		    encode:function(buf)
		    {
       			EncodeUtils.uInt16ToByte(tb.banker_cards.length, buf);
       			for (let i = 0; i < tb.banker_cards.length; ++i)
				{
		    		EncodeUtils.int32ToByte(tb.banker_cards[i], buf);
       			}
       			EncodeUtils.uInt16ToByte(tb.player_cards.length, buf);
       			for (let i = 0; i < tb.player_cards.length; ++i)
				{
		    		EncodeUtils.int32ToByte(tb.player_cards[i], buf);
       			}
    		    EncodeUtils.int32ToByte(tb.banker_point, buf);
    		    EncodeUtils.int32ToByte(tb.player_point, buf);
        		EncodeUtils.uInt16ToByte(tb.settlement_list.length, buf);
        		for (let i = 0; i < tb.settlement_list.length; ++i)
				{
            		tb.settlement_list[i].encode(buf);
	     		}
    			EncodeUtils.int64ToByte(tb.others_get_money, buf);
    		    EncodeUtils.int32ToByte(tb.record, buf);
    			EncodeUtils.utf8StrtoBytes(tb.client_key, buf);
    			EncodeUtils.utf8StrtoBytes(tb.server_key, buf);
    			EncodeUtils.utf8StrtoBytes(tb.video, buf);
    	    },
    		decode:function(buf, index)
			{
				let startIndex = index;
        		let banker_cards_len = EncodeUtils.ByteToUint16(buf, startIndex);
        		startIndex += 2;
        		for(let i = 0; i < banker_cards_len; ++i)
		 		{
             		tb.banker_cards.push(EncodeUtils.ByteToint32(buf, startIndex));
					startIndex += 4;
        		}
        		let player_cards_len = EncodeUtils.ByteToUint16(buf, startIndex);
        		startIndex += 2;
        		for(let i = 0; i < player_cards_len; ++i)
		 		{
             		tb.player_cards.push(EncodeUtils.ByteToint32(buf, startIndex));
					startIndex += 4;
        		}
        		tb.banker_point = EncodeUtils.ByteToint32(buf, startIndex);
				startIndex += 4;
        		tb.player_point = EncodeUtils.ByteToint32(buf, startIndex);
				startIndex += 4;
        		let settlement_list_len = EncodeUtils.ByteToUint16(buf, startIndex);
        		startIndex += 2;
        		for(let i = 0; i < settlement_list_len; ++i)
				{
            		let tmp = baijiale_settlement_item();
            		startIndex += tmp.decode(buf, startIndex);
            		tb.settlement_list.push(tmp);
        		}
        		tb.others_get_money = EncodeUtils.ByteToint64(buf, startIndex);
				startIndex += 8;
        		tb.record = EncodeUtils.ByteToint32(buf, startIndex);
				startIndex += 4;
				let client_key_value = EncodeUtils.byteToString(buf, startIndex);
				tb.client_key = client_key_value[0];
 				startIndex += client_key_value[1];
				let server_key_value = EncodeUtils.byteToString(buf, startIndex);
				tb.server_key = server_key_value[0];
 				startIndex += server_key_value[1];
				let video_value = EncodeUtils.byteToString(buf, startIndex);
				tb.video = video_value[0];
 				startIndex += video_value[1];
				return startIndex - index;
			},
    		build:function(buf)
			{
        		EncodeUtils.uInt32ToByte(NetMsgType.msgType["msg_notify_baijiale_settlement"], buf);
        		return tb.encode(buf);
    		}
		};
    	return tb;
	}
