    export function shaibao_config()
    {
        let tb = {
    	    role_count : 0,
    	    min_bet : 0,
    	    need_chip : 0,
    	    banker_chip : 0,
    	    banker_type : 0,
    	    max_chip : 0,
    	    role_bet_limit : 0,
    	    system_bet_limit : 0,
    	    chip_list : [],
    	    default_chip_list : [],
    	    my_chip_base : 0,
    	    bet_time : 0,
    	    sync_chip_time : 0,
    	    dice_time : 0,
    	    settlement_time : 0,
    	    count_down_time : 0,
			getMsgID:function()
			{
   				return NetMsgType.msgType["msg_shaibao_config"];
    		},
		    encode:function(buf)
		    {
    			EncodeUtils.int64ToByte(tb.role_count, buf);
    			EncodeUtils.int64ToByte(tb.min_bet, buf);
    			EncodeUtils.int64ToByte(tb.need_chip, buf);
    			EncodeUtils.int64ToByte(tb.banker_chip, buf);
    			EncodeUtils.int64ToByte(tb.banker_type, buf);
    			EncodeUtils.int64ToByte(tb.max_chip, buf);
    			EncodeUtils.int64ToByte(tb.role_bet_limit, buf);
    			EncodeUtils.int64ToByte(tb.system_bet_limit, buf);
       			EncodeUtils.uInt16ToByte(tb.chip_list.length, buf);
       			for (let i = 0; i < tb.chip_list.length; ++i)
				{
		    		EncodeUtils.int32ToByte(tb.chip_list[i], buf);
       			}
       			EncodeUtils.uInt16ToByte(tb.default_chip_list.length, buf);
       			for (let i = 0; i < tb.default_chip_list.length; ++i)
				{
		    		EncodeUtils.int32ToByte(tb.default_chip_list[i], buf);
       			}
    			EncodeUtils.int64ToByte(tb.my_chip_base, buf);
    			EncodeUtils.int64ToByte(tb.bet_time, buf);
    			EncodeUtils.int64ToByte(tb.sync_chip_time, buf);
    			EncodeUtils.int64ToByte(tb.dice_time, buf);
    			EncodeUtils.int64ToByte(tb.settlement_time, buf);
    			EncodeUtils.int64ToByte(tb.count_down_time, buf);
    	    },
    		decode:function(buf, index)
			{
				let startIndex = index;
        		tb.role_count = EncodeUtils.ByteToint64(buf, startIndex);
				startIndex += 8;
        		tb.min_bet = EncodeUtils.ByteToint64(buf, startIndex);
				startIndex += 8;
        		tb.need_chip = EncodeUtils.ByteToint64(buf, startIndex);
				startIndex += 8;
        		tb.banker_chip = EncodeUtils.ByteToint64(buf, startIndex);
				startIndex += 8;
        		tb.banker_type = EncodeUtils.ByteToint64(buf, startIndex);
				startIndex += 8;
        		tb.max_chip = EncodeUtils.ByteToint64(buf, startIndex);
				startIndex += 8;
        		tb.role_bet_limit = EncodeUtils.ByteToint64(buf, startIndex);
				startIndex += 8;
        		tb.system_bet_limit = EncodeUtils.ByteToint64(buf, startIndex);
				startIndex += 8;
        		let chip_list_len = EncodeUtils.ByteToUint16(buf, startIndex);
        		startIndex += 2;
        		for(let i = 0; i < chip_list_len; ++i)
		 		{
             		tb.chip_list.push(EncodeUtils.ByteToint32(buf, startIndex));
					startIndex += 4;
        		}
        		let default_chip_list_len = EncodeUtils.ByteToUint16(buf, startIndex);
        		startIndex += 2;
        		for(let i = 0; i < default_chip_list_len; ++i)
		 		{
             		tb.default_chip_list.push(EncodeUtils.ByteToint32(buf, startIndex));
					startIndex += 4;
        		}
        		tb.my_chip_base = EncodeUtils.ByteToint64(buf, startIndex);
				startIndex += 8;
        		tb.bet_time = EncodeUtils.ByteToint64(buf, startIndex);
				startIndex += 8;
        		tb.sync_chip_time = EncodeUtils.ByteToint64(buf, startIndex);
				startIndex += 8;
        		tb.dice_time = EncodeUtils.ByteToint64(buf, startIndex);
				startIndex += 8;
        		tb.settlement_time = EncodeUtils.ByteToint64(buf, startIndex);
				startIndex += 8;
        		tb.count_down_time = EncodeUtils.ByteToint64(buf, startIndex);
				startIndex += 8;
				return startIndex - index;
			},
    		build:function(buf)
			{
        		EncodeUtils.uInt32ToByte(NetMsgType.msgType["msg_shaibao_config"], buf);
        		return tb.encode(buf);
    		}
		};
    	return tb;
	}
