    export function notify_shaibao_room_info()
    {
        let tb = {
    	    game_status : 0,
    	    roles : [],
    	    config : shaibao_config(),
    	    all_chips : shaibao_desktop_chip(),
    	    self_chips : shaibao_desktop_chip(),
    	    my_chips : [],
    	    record_list : [],
    	    banker_base : shaibao_game_role_info(),
    	    banker_base_list : [],
    	    role_count : 0,
    	    end_time : 0,
			getMsgID:function()
			{
   				return NetMsgType.msgType["msg_notify_shaibao_room_info"];
    		},
		    encode:function(buf)
		    {
    		    EncodeUtils.int32ToByte(tb.game_status, buf);
        		EncodeUtils.uInt16ToByte(tb.roles.length, buf);
        		for (let i = 0; i < tb.roles.length; ++i)
				{
            		tb.roles[i].encode(buf);
	     		}
        		tb.config.encode(buf);
        		tb.all_chips.encode(buf);
        		tb.self_chips.encode(buf);
       			EncodeUtils.uInt16ToByte(tb.my_chips.length, buf);
       			for (let i = 0; i < tb.my_chips.length; ++i)
				{
		    		EncodeUtils.int64ToByte(tb.my_chips[i], buf);
       			}
        		EncodeUtils.uInt16ToByte(tb.record_list.length, buf);
        		for (let i = 0; i < tb.record_list.length; ++i)
				{
            		tb.record_list[i].encode(buf);
	     		}
        		tb.banker_base.encode(buf);
        		EncodeUtils.uInt16ToByte(tb.banker_base_list.length, buf);
        		for (let i = 0; i < tb.banker_base_list.length; ++i)
				{
            		tb.banker_base_list[i].encode(buf);
	     		}
    			EncodeUtils.int64ToByte(tb.role_count, buf);
    			EncodeUtils.int64ToByte(tb.end_time, buf);
    	    },
    		decode:function(buf, index)
			{
				let startIndex = index;
        		tb.game_status = EncodeUtils.ByteToint32(buf, startIndex);
				startIndex += 4;
        		let roles_len = EncodeUtils.ByteToUint16(buf, startIndex);
        		startIndex += 2;
        		for(let i = 0; i < roles_len; ++i)
				{
            		let tmp = shaibao_game_role_info();
            		startIndex += tmp.decode(buf, startIndex);
            		tb.roles.push(tmp);
        		}
        		startIndex += tb.config.decode(buf, startIndex);
        		startIndex += tb.all_chips.decode(buf, startIndex);
        		startIndex += tb.self_chips.decode(buf, startIndex);
        		let my_chips_len = EncodeUtils.ByteToUint16(buf, startIndex);
        		startIndex += 2;
        		for(let i = 0; i < my_chips_len; ++i)
		 		{
             		tb.my_chips.push(EncodeUtils.ByteToint64(buf, startIndex));
					startIndex += 8;
        		}
        		let record_list_len = EncodeUtils.ByteToUint16(buf, startIndex);
        		startIndex += 2;
        		for(let i = 0; i < record_list_len; ++i)
				{
            		let tmp = shaibao_shaizi_info();
            		startIndex += tmp.decode(buf, startIndex);
            		tb.record_list.push(tmp);
        		}
        		startIndex += tb.banker_base.decode(buf, startIndex);
        		let banker_base_list_len = EncodeUtils.ByteToUint16(buf, startIndex);
        		startIndex += 2;
        		for(let i = 0; i < banker_base_list_len; ++i)
				{
            		let tmp = room_role_base();
            		startIndex += tmp.decode(buf, startIndex);
            		tb.banker_base_list.push(tmp);
        		}
        		tb.role_count = EncodeUtils.ByteToint64(buf, startIndex);
				startIndex += 8;
        		tb.end_time = EncodeUtils.ByteToint64(buf, startIndex);
				startIndex += 8;
				return startIndex - index;
			},
    		build:function(buf)
			{
        		EncodeUtils.uInt32ToByte(NetMsgType.msgType["msg_notify_shaibao_room_info"], buf);
        		return tb.encode(buf);
    		}
		};
    	return tb;
	}
