    export function notify_shaibao_settlement()
    {
        let tb = {
    	    dicees : [],
    	    win_area : [],
    	    my_win_area : [],
    	    settlement_list : [],
    	    others_get_money : 0,
    	    client_seed : '',
    	    server_plaintext : '',
    	    server_ciphertext : '',
    	    complete_ciphertext : '',
    	    shaizi_list : [],
			getMsgID:function()
			{
   				return NetMsgType.msgType["msg_notify_shaibao_settlement"];
    		},
		    encode:function(buf)
		    {
       			EncodeUtils.uInt16ToByte(tb.dicees.length, buf);
       			for (let i = 0; i < tb.dicees.length; ++i)
				{
		    		EncodeUtils.int32ToByte(tb.dicees[i], buf);
       			}
       			EncodeUtils.uInt16ToByte(tb.win_area.length, buf);
       			for (let i = 0; i < tb.win_area.length; ++i)
				{
		    		EncodeUtils.int32ToByte(tb.win_area[i], buf);
       			}
       			EncodeUtils.uInt16ToByte(tb.my_win_area.length, buf);
       			for (let i = 0; i < tb.my_win_area.length; ++i)
				{
		    		EncodeUtils.int32ToByte(tb.my_win_area[i], buf);
       			}
        		EncodeUtils.uInt16ToByte(tb.settlement_list.length, buf);
        		for (let i = 0; i < tb.settlement_list.length; ++i)
				{
            		tb.settlement_list[i].encode(buf);
	     		}
    			EncodeUtils.int64ToByte(tb.others_get_money, buf);
    			EncodeUtils.utf8StrtoBytes(tb.client_seed, buf);
    			EncodeUtils.utf8StrtoBytes(tb.server_plaintext, buf);
    			EncodeUtils.utf8StrtoBytes(tb.server_ciphertext, buf);
    			EncodeUtils.utf8StrtoBytes(tb.complete_ciphertext, buf);
        		EncodeUtils.uInt16ToByte(tb.shaizi_list.length, buf);
        		for (let i = 0; i < tb.shaizi_list.length; ++i)
				{
            		tb.shaizi_list[i].encode(buf);
	     		}
    	    },
    		decode:function(buf, index)
			{
				let startIndex = index;
        		let dicees_len = EncodeUtils.ByteToUint16(buf, startIndex);
        		startIndex += 2;
        		for(let i = 0; i < dicees_len; ++i)
		 		{
             		tb.dicees.push(EncodeUtils.ByteToint32(buf, startIndex));
					startIndex += 4;
        		}
        		let win_area_len = EncodeUtils.ByteToUint16(buf, startIndex);
        		startIndex += 2;
        		for(let i = 0; i < win_area_len; ++i)
		 		{
             		tb.win_area.push(EncodeUtils.ByteToint32(buf, startIndex));
					startIndex += 4;
        		}
        		let my_win_area_len = EncodeUtils.ByteToUint16(buf, startIndex);
        		startIndex += 2;
        		for(let i = 0; i < my_win_area_len; ++i)
		 		{
             		tb.my_win_area.push(EncodeUtils.ByteToint32(buf, startIndex));
					startIndex += 4;
        		}
        		let settlement_list_len = EncodeUtils.ByteToUint16(buf, startIndex);
        		startIndex += 2;
        		for(let i = 0; i < settlement_list_len; ++i)
				{
            		let tmp = shaibao_settlement_item();
            		startIndex += tmp.decode(buf, startIndex);
            		tb.settlement_list.push(tmp);
        		}
        		tb.others_get_money = EncodeUtils.ByteToint64(buf, startIndex);
				startIndex += 8;
				let client_seed_value = EncodeUtils.byteToString(buf, startIndex);
				tb.client_seed = client_seed_value[0];
 				startIndex += client_seed_value[1];
				let server_plaintext_value = EncodeUtils.byteToString(buf, startIndex);
				tb.server_plaintext = server_plaintext_value[0];
 				startIndex += server_plaintext_value[1];
				let server_ciphertext_value = EncodeUtils.byteToString(buf, startIndex);
				tb.server_ciphertext = server_ciphertext_value[0];
 				startIndex += server_ciphertext_value[1];
				let complete_ciphertext_value = EncodeUtils.byteToString(buf, startIndex);
				tb.complete_ciphertext = complete_ciphertext_value[0];
 				startIndex += complete_ciphertext_value[1];
        		let shaizi_list_len = EncodeUtils.ByteToUint16(buf, startIndex);
        		startIndex += 2;
        		for(let i = 0; i < shaizi_list_len; ++i)
				{
            		let tmp = shaibao_shaizi_item();
            		startIndex += tmp.decode(buf, startIndex);
            		tb.shaizi_list.push(tmp);
        		}
				return startIndex - index;
			},
    		build:function(buf)
			{
        		EncodeUtils.uInt32ToByte(NetMsgType.msgType["msg_notify_shaibao_settlement"], buf);
        		return tb.encode(buf);
    		}
		};
    	return tb;
	}
