    export function notify_lhd_stage()
    {
        let tb = {
    	    stageIndex : 0,
    	    end_time : stime(),
    	    balance_result : 0,
    	    dice_num : [],
    	    money : 0,
    	    money2 : 0,
    	    cur_money : 0,
    	    end_time2 : 0,
    	    all_user_count : 0,
    	    shen_suan_zi : lhd_shen_suan_zi_info(),
    	    da_fu_hao : lhd_da_fu_hao_info(),
    	    video : '',
    	    client_key : '',
    	    client_hash : '',
    	    server_hash : '',
			getMsgID:function()
			{
   				return NetMsgType.msgType["msg_notify_lhd_stage"];
    		},
		    encode:function(buf)
		    {
    		    EncodeUtils.int32ToByte(tb.stageIndex, buf);
        		tb.end_time.encode(buf);
    		    EncodeUtils.int32ToByte(tb.balance_result, buf);
       			EncodeUtils.uInt16ToByte(tb.dice_num.length, buf);
       			for (let i = 0; i < tb.dice_num.length; ++i)
				{
		    		EncodeUtils.int32ToByte(tb.dice_num[i], buf);
       			}
    			EncodeUtils.int64ToByte(tb.money, buf);
    			EncodeUtils.int64ToByte(tb.money2, buf);
    			EncodeUtils.int64ToByte(tb.cur_money, buf);
    			EncodeUtils.int64ToByte(tb.end_time2, buf);
    		    EncodeUtils.int32ToByte(tb.all_user_count, buf);
        		tb.shen_suan_zi.encode(buf);
        		tb.da_fu_hao.encode(buf);
    			EncodeUtils.utf8StrtoBytes(tb.video, buf);
    			EncodeUtils.utf8StrtoBytes(tb.client_key, buf);
    			EncodeUtils.utf8StrtoBytes(tb.client_hash, buf);
    			EncodeUtils.utf8StrtoBytes(tb.server_hash, buf);
    	    },
    		decode:function(buf, index)
			{
				let startIndex = index;
        		tb.stageIndex = EncodeUtils.ByteToint32(buf, startIndex);
				startIndex += 4;
        		startIndex += tb.end_time.decode(buf, startIndex);
        		tb.balance_result = EncodeUtils.ByteToint32(buf, startIndex);
				startIndex += 4;
        		let dice_num_len = EncodeUtils.ByteToUint16(buf, startIndex);
        		startIndex += 2;
        		for(let i = 0; i < dice_num_len; ++i)
		 		{
             		tb.dice_num.push(EncodeUtils.ByteToint32(buf, startIndex));
					startIndex += 4;
        		}
        		tb.money = EncodeUtils.ByteToint64(buf, startIndex);
				startIndex += 8;
        		tb.money2 = EncodeUtils.ByteToint64(buf, startIndex);
				startIndex += 8;
        		tb.cur_money = EncodeUtils.ByteToint64(buf, startIndex);
				startIndex += 8;
        		tb.end_time2 = EncodeUtils.ByteToint64(buf, startIndex);
				startIndex += 8;
        		tb.all_user_count = EncodeUtils.ByteToint32(buf, startIndex);
				startIndex += 4;
        		startIndex += tb.shen_suan_zi.decode(buf, startIndex);
        		startIndex += tb.da_fu_hao.decode(buf, startIndex);
				let video_value = EncodeUtils.byteToString(buf, startIndex);
				tb.video = video_value[0];
 				startIndex += video_value[1];
				let client_key_value = EncodeUtils.byteToString(buf, startIndex);
				tb.client_key = client_key_value[0];
 				startIndex += client_key_value[1];
				let client_hash_value = EncodeUtils.byteToString(buf, startIndex);
				tb.client_hash = client_hash_value[0];
 				startIndex += client_hash_value[1];
				let server_hash_value = EncodeUtils.byteToString(buf, startIndex);
				tb.server_hash = server_hash_value[0];
 				startIndex += server_hash_value[1];
				return startIndex - index;
			},
    		build:function(buf)
			{
        		EncodeUtils.uInt32ToByte(NetMsgType.msgType["msg_notify_lhd_stage"], buf);
        		return tb.encode(buf);
    		}
		};
    	return tb;
	}
