    export function notify_lhd_bet()
    {
        let tb = {
    	    money : [],
    	    bet_player_num : [],
    	    other_user_betmoney : [],
    	    dafuhao_bet_money : 0,
    	    shensuanzi_bet_money : 0,
			getMsgID:function()
			{
   				return NetMsgType.msgType["msg_notify_lhd_bet"];
    		},
		    encode:function(buf)
		    {
       			EncodeUtils.uInt16ToByte(tb.money.length, buf);
       			for (let i = 0; i < tb.money.length; ++i)
				{
		    		EncodeUtils.int64ToByte(tb.money[i], buf);
       			}
       			EncodeUtils.uInt16ToByte(tb.bet_player_num.length, buf);
       			for (let i = 0; i < tb.bet_player_num.length; ++i)
				{
		    		EncodeUtils.int32ToByte(tb.bet_player_num[i], buf);
       			}
       			EncodeUtils.uInt16ToByte(tb.other_user_betmoney.length, buf);
       			for (let i = 0; i < tb.other_user_betmoney.length; ++i)
				{
		    		EncodeUtils.int64ToByte(tb.other_user_betmoney[i], buf);
       			}
    		    EncodeUtils.int32ToByte(tb.dafuhao_bet_money, buf);
    		    EncodeUtils.int32ToByte(tb.shensuanzi_bet_money, buf);
    	    },
    		decode:function(buf, index)
			{
				let startIndex = index;
        		let money_len = EncodeUtils.ByteToUint16(buf, startIndex);
        		startIndex += 2;
        		for(let i = 0; i < money_len; ++i)
		 		{
             		tb.money.push(EncodeUtils.ByteToint64(buf, startIndex));
					startIndex += 8;
        		}
        		let bet_player_num_len = EncodeUtils.ByteToUint16(buf, startIndex);
        		startIndex += 2;
        		for(let i = 0; i < bet_player_num_len; ++i)
		 		{
             		tb.bet_player_num.push(EncodeUtils.ByteToint32(buf, startIndex));
					startIndex += 4;
        		}
        		let other_user_betmoney_len = EncodeUtils.ByteToUint16(buf, startIndex);
        		startIndex += 2;
        		for(let i = 0; i < other_user_betmoney_len; ++i)
		 		{
             		tb.other_user_betmoney.push(EncodeUtils.ByteToint64(buf, startIndex));
					startIndex += 8;
        		}
        		tb.dafuhao_bet_money = EncodeUtils.ByteToint32(buf, startIndex);
				startIndex += 4;
        		tb.shensuanzi_bet_money = EncodeUtils.ByteToint32(buf, startIndex);
				startIndex += 4;
				return startIndex - index;
			},
    		build:function(buf)
			{
        		EncodeUtils.uInt32ToByte(NetMsgType.msgType["msg_notify_lhd_bet"], buf);
        		return tb.encode(buf);
    		}
		};
    	return tb;
	}
