    export function notify_lhd_banker_queue()
    {
        let tb = {
    	    role_ids : [],
    	    nicknames : [],
    	    head_photo : [],
    	    moneys : [],
			getMsgID:function()
			{
   				return NetMsgType.msgType["msg_notify_lhd_banker_queue"];
    		},
		    encode:function(buf)
		    {
       			EncodeUtils.uInt16ToByte(tb.role_ids.length, buf);
       			for (let i = 0; i < tb.role_ids.length; ++i)
				{
		    		EncodeUtils.int64ToByte(tb.role_ids[i], buf);
       			}
       			EncodeUtils.uInt16ToByte(tb.nicknames.length, buf);
       			for (let i = 0; i < tb.nicknames.length; ++i)
				{
		    		EncodeUtils.utf8StrtoBytes(tb.nicknames[i], buf);
       			}
       			EncodeUtils.uInt16ToByte(tb.head_photo.length, buf);
       			for (let i = 0; i < tb.head_photo.length; ++i)
				{
		    		EncodeUtils.utf8StrtoBytes(tb.head_photo[i], buf);
       			}
       			EncodeUtils.uInt16ToByte(tb.moneys.length, buf);
       			for (let i = 0; i < tb.moneys.length; ++i)
				{
		    		EncodeUtils.int64ToByte(tb.moneys[i], buf);
       			}
    	    },
    		decode:function(buf, index)
			{
				let startIndex = index;
        		let role_ids_len = EncodeUtils.ByteToUint16(buf, startIndex);
        		startIndex += 2;
        		for(let i = 0; i < role_ids_len; ++i)
		 		{
             		tb.role_ids.push(EncodeUtils.ByteToint64(buf, startIndex));
					startIndex += 8;
        		}
        		let nicknames_len = EncodeUtils.ByteToUint16(buf, startIndex);
        		startIndex += 2;
        		for(let i = 0; i < nicknames_len; ++i)
		 		{
					let nicknames_value = EncodeUtils.byteToString(buf, startIndex);
					tb.nicknames.push(nicknames_value[0]);
					startIndex += nicknames_value[1];
        		}
        		let head_photo_len = EncodeUtils.ByteToUint16(buf, startIndex);
        		startIndex += 2;
        		for(let i = 0; i < head_photo_len; ++i)
		 		{
					let head_photo_value = EncodeUtils.byteToString(buf, startIndex);
					tb.head_photo.push(head_photo_value[0]);
					startIndex += head_photo_value[1];
        		}
        		let moneys_len = EncodeUtils.ByteToUint16(buf, startIndex);
        		startIndex += 2;
        		for(let i = 0; i < moneys_len; ++i)
		 		{
             		tb.moneys.push(EncodeUtils.ByteToint64(buf, startIndex));
					startIndex += 8;
        		}
				return startIndex - index;
			},
    		build:function(buf)
			{
        		EncodeUtils.uInt32ToByte(NetMsgType.msgType["msg_notify_lhd_banker_queue"], buf);
        		return tb.encode(buf);
    		}
		};
    	return tb;
	}
